	('form_17', 'ቅጽ 17፡  በየደረጃው በኮሚሽን አባላትና አመራሮች ላይ የተወሰደ ርምጃዎችና ቅሬታ ያቀረቡ የሚያሳይ ሠንጠረዥ', '[{"key": "የተወሰደ የእርምት ርምጃዎች", "subKeys": ["በኮሚሽን አባላት", "በቅ/ጽ/ቤት ኃላፊዎች", "ድምር"]}, {"key": "ርምጃ ከተወሰደባቸው ቅሬታ ያቀረቡና ምላሽ የተሰጣቸው/ምርመራ", "subKeys": ["ብዛት", "የተፈታ", "%"]}]', '2026-07-10 11:05:45.253372+00', '2026-07-10 11:05:45.253372+00'),
