	('form_21', 'ቅጽ 21፡  በየደረጃው በሚገኙ የፓርቲ ጽ/ቤቶች የፓርቲ ገቢ አሰባሰብ አፈጻጸም የሚያሳይ ሠንጠረዥ', '[{"key": "የአባልነት መዋጮ ገቢ", "subKeys": ["እቅድ", "ክንውን", "%"]}, {"key": "ልዩ ልዩ ገቢ(ድጋፍ፣ የመጽሄት ሽያጭ፣ ውዝፍ)", "subKeys": ["እቅድ", "ክንውን", "%"]}, {"key": "በጠቅላላው የተሰበሰበው ገቢ በብር", "subKeys": ["እቅድ", "ክንውን", "%"]}, {"key": "በ9 ወራት ውስጥ ለፓርቲ ዋና ጽ/ቤት %20 ፈሰስ የተደረገ", "subKeys": ["እቅድ", "ክንውን", "%"]}]', '2026-07-10 11:05:45.253372+00', '2026-07-10 11:05:45.253372+00'),
	('form_22', 'ቅጽ 22፡ በክልል/ከተማ ኮሚሽን እና ቅርንጫፍ ጽ/ቤት ደረጃ  የመደበኛ የግንኙነት አፈጻጸም መረጃ ማጠናቀሪያ ቅፅ', '[{"key": "የኮሚሽን መድረክ", "subKeys": ["እቅድ", "ክንውን"]}, {"key": "የኮሚሽን ሥራ አመራር ኮሚቴ መድረክ", "subKeys": ["እቅድ", "ክንውን"]}, {"key": "የኮሚሽኑ ቅ/ጽ/ቤት ማኔጅመንት ኮሚቴ መድረክ", "subKeys": ["እቅድ", "ክንውን"]}, {"key": "ለክልል ተጠሪ ከሆኑ ከዞን/ከተማ/ልዩወረዳ ኮሚሽን ጋር የተደረገ መድረክ", "subKeys": ["እቅድ", "ክንውን"]}, {"key": "ለክልል ተጠሪ ከሆኑ የዞን/ከተማ/ልዩወረዳ የኮሚሽን ቅ/ጽ/ቤት ኃላፊዎች ጋር የተደረገ መድረክ", "subKeys": ["እቅድ", "ክንውን"]}, {"key": "ከክልል/ከተማ ፓርቲ ቅ/ጽ/ቤት ሥራ አመራር ኮሚቴ ጋርየተደረገ", "subKeys": ["እቅድ", "ክንውን"]}]', '2026-07-10 11:05:45.253372+00', '2026-07-10 11:05:45.253372+00'),
	('form_23', 'ቅጽ 23፡  በኮሚሽኑ የተመዘገቡ ውጤቶች አፈጻጸም የሚያሳይ ሠንጠረዥ', '[{"key": "የኢንስፔክሽን ግኝቶች የአሰራር ጥሰቶች ብዛት", "subKeys": []}, {"key": "ከአባልነት ተሰናብተው የተመለሱ አባላት ብዛት", "subKeys": []}, {"key": "ከኃላፊነት ተነስተው የተመለሱ አመራሮች ብዛት", "subKeys": []}, {"key": "በኢንስፔክሽን የተገኘ የፓርቲ መዋጮ የማይከፍሉ አባላት", "subKeys": []}, {"key": "ለሌላ ዓላማ ውሎ የነበረ የተመለሰ የፓርቲ ገንዘብ ብዛት", "subKeys": []}, {"key": "ኦዲት እንዲያስደርጉ የተደረገ የፓርቲ ቅ/ጽ/ቤቶች ብዛት", "subKeys": []}, {"key": "እንዲመለስ የተደረገ የኦዲት ግኝቶች በብር", "subKeys": []}, {"key": "እንዲመዘግቡ የተደረገ የፓርቲ ንብረት ብዛት", "subKeys": []}, {"key": "የንብረት ባለቤትነት ሰነድ እንዲወጣላቸው የተደረገ ብዛት", "subKeys": []}, {"key": "በፀረ-ሙስና ንቅናቄ የተመዘገበ ውጤት", "subKeys": ["ሀብት ማስመዝገብ ብዛት", "ሀብት ማስመዝገብ ብር", "የተመለሰ ገንዘብ", "ለህግ የቀረበ በሰው"]}]', '2026-07-10 11:05:45.253372+00', '2026-07-10 11:05:45.253372+00'),
